noncompliant:
switch (value) {
  case 1:
    handle1();
    break;
  case 2:
    handle2();
    break;
  case 3:
    handle3();
    break;
  case 4:
    handle4();
    break;
  case 5:
    handle5();
    break;
  case 6:
    handle6();
    break;
  case 7:
    handle7();
    break;
  case 8:
    handle8();
    break;
  case 9:
    handle9();
    break;
  case 10:
    handle10();
    break;
  // ... many more cases
}

compliant:
// Use a lookup table or function pointer array instead
static void (*handlers[])(void) = {
  handle1, handle2, handle3, handle4, handle5,
  handle6, handle7, handle8, handle9, handle10
};

if (value >= 1 && value <= 10) {
  handlers[value - 1]();
}

// Or use if-else for fewer cases
if (value == 1) {
  handle1();
} else if (value == 2) {
  handle2();
} else if (value == 3) {
  handle3();
} else {
  handleDefault();
}
